export const getListAdminAccountsUrl = (params?: ListAdminAccountsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/v1/accounts?${stringifiedParams}`
    : `/api/v1/accounts`;
};

export const listAdminAccounts = async (
  params?: ListAdminAccountsParams,
  options?: RequestInit
): Promise<listAdminAccountsResponse> => {
  const res = await fetch(getListAdminAccountsUrl(params), {
    ...options,
    method: 'GET',
  });

  const body = [204, 205, 304].includes(res.status) ? null : await res.text();

  const data: listAdminAccountsResponse['data'] = body ? JSON.parse(body) : {};
  return { data, status: res.status, headers: res.headers } as listAdminAccountsResponse;
};

